INSERT INTO `albums` (`id`, `name`, `slug`, `artist_id`, `year`, `cover_image`, `description`, `created_at`, `updated_at`) VALUES
(1, 'Patra', 'patra-1770093641', 1, '2026', 'images/albums/1770093641_album.jpg', 'Letters within letters to let her know, that in all of my loving she is all I’ve known. For when the night falls, and thoughts surround you and force a conversation, you realise neither time nor space can create distance from her of any kind. And so each day becomes a mere addition to how long you’ve spent missing her. Each morning becomes a promise to face another night, once more, belonging to only her.', '2026-02-02 17:10:41', '2026-02-02 17:10:41');
INSERT INTO `artists` (`id`, `name_english`, `name_nepali`, `slug`, `bio`, `date_of_birth`, `profile_image`, `cover_image`, `social_links`, `is_verified`, `views_count`, `created_at`, `updated_at`) VALUES
(1, 'Sajjan Raj Vaidya', 'सज्जन राज वैद्य', 'sajjan-raj-vaidya', 'Sajjan Raj Vaidya is a Nepali singer-songwriter and music producer born on September 10, 1993, in Kathmandu, Nepal, known for his soulful voice and emotional songwriting. He rose to fame with popular songs like Hawaijahaj, Chitthi Bhitra, Sasto Mutu, and Hataarindai, Bataasindai, and is admired for blending acoustic pop with meaningful lyrics about love, identity, and social themes. Currently based in New York City, he continues to influence modern Nepali music with his unique style and storytelling.', '1993-09-10', 'artists/profiles/xWhuNrSjLKMcbbX3ToEwMVglpl8lrkyOfPMymik0.jpg', 'artists/covers/CafJJpLubkzkIC4bj1YKVXqkriRpyAAqDwzKv63M.jpg', '{\"youtube\":\"https:\\/\\/www.youtube.com\\/channel\\/UClFO6ULKU2XXQ_zb76JMUPQ\",\"facebook\":\"https:\\/\\/facebook.com\\/sajjanrajvaidya\",\"instagram\":\"https:\\/\\/instagram.com\\/sajjanrajvaidya\",\"tiktok\":\"https:\\/\\/www.tiktok.com\\/@sajjanrajvaidya\",\"spotify\":\"https:\\/\\/open.spotify.com\\/artist\\/1deQzOQwArAsUgm2WdjtyI\",\"apple_music\":\"https:\\/\\/music.apple.com\\/np\\/artist\\/sajjan-raj-vaidya\\/1206974063\",\"website\":\"https:\\/\\/sajjanrajvaidya.com\"}', 1, 102, '2026-02-02 14:55:32', '2026-02-13 15:27:10'),
(2, 'Jhuma Limbu', 'झुमा लिम्बु', 'jhuma-limbu', 'Jhuma Limbu is a Nepalese singer, folk musician. She has been actively researching about various Nepali folk music genres and instruments.', NULL, 'artists/profiles/rllMN9Px8ktED4tDjl959VA2Xl48JBFwqT5MFuJM.webp', 'artists/covers/9GVA2hCO8swF9gO3NdPqGIJKFtOlbm3kAFLS6soo.jpg', '{\"youtube\":\"https:\\/\\/www.youtube.com\\/c\\/JhumaLimbu\",\"facebook\":\"https:\\/\\/www.facebook.com\\/jhumalimbunepal\\/\",\"instagram\":\"https:\\/\\/www.instagram.com\\/limbujhuma\",\"spotify\":\"https:\\/\\/open.spotify.com\\/artist\\/5dD7OffChxQLMkhYwnFMW5\",\"apple_music\":\"https:\\/\\/music.apple.com\\/us\\/artist\\/jhuma-limbu\\/670146163\",\"website\":\"https:\\/\\/www.jhumalimbu.com\\/\"}', 1, 55, '2026-02-02 15:21:57', '2026-02-13 21:12:21'),
(4, 'Wiz Khalifa', 'विज खलिफा', 'wiz-khalifa', 'Wiz Khalifa (born Cameron Jibril Thomaz on September 8, 1987) is an American rapper, singer, and songwriter known for his laid-back style and catchy hooks. He rose to global fame with the hit single “Black and Yellow” in 2010, which topped the Billboard Hot 100. Wiz is also known for songs like “See You Again,” “Young, Wild & Free,” and “We Dem Boyz.” Blending hip-hop with pop influences, he’s built a strong brand around his music, fashion, and cannabis advocacy, making him one of the most recognizable artists of his generation.', '1987-09-08', 'artists/profiles/msyUgx5B60yckW78zGePCwBLdwJ90UtYGJT86KcA.webp', 'artists/covers/Ap12tyj3U8wml5V9BNjVExtIViUqCF4foK6r89Ry.jpg', '{\"youtube\":\"https:\\/\\/www.youtube.com\\/channel\\/UCVp3nfGRxmMadNDuVbJSk8A\",\"facebook\":\"https:\\/\\/facebook.com\\/wizkhalifa\",\"instagram\":\"https:\\/\\/instagram.com\\/wizkhalifa\",\"apple_music\":\"https:\\/\\/itunes.apple.com\\/us\\/artist\\/wiz-khalifa\\/id201714418\",\"website\":\"https:\\/\\/wizkhalifa.com\\/\"}', 1, 17, '2026-02-03 11:13:17', '2026-02-11 17:24:34');
