INSERT INTO `genres` (`id`, `name`, `slug`, `description`, `created_at`, `updated_at`) VALUES
(1, 'Nepali Pop/Soft Rock', 'nepali-popsoft-rock', 'A smooth blend of Nepali pop melodies and soft rock vibes, featuring heartfelt lyrics, soothing guitars, and emotional vocals that speak straight to the soul.', '2026-02-02 17:07:32', '2026-02-02 17:07:32'),
(2, 'Pop-Rap', 'pop-rap', 'Pop-Rap is a genre that blends the catchy melodies and broad appeal of pop music with the rhythm, flow, and lyrical style of rap. It’s known for its smooth hooks, upbeat production, and relatable themes like love, ambition, and everyday life—making it accessible, radio-friendly, and widely popular across audiences.', '2026-02-03 11:00:47', '2026-02-03 11:00:47'),
