INSERT INTO `lyrics` (`id`, `song_id`, `content_unicode`, `content_romanized`, `created_at`, `updated_at`) VALUES
(1, 1, 'के खाले माया यो? दिनदिनै कमाउनुपर्ने रे\r\nमनले पुग्दैन, सिरमाथि चढाउनुपर्ने रे\r\nयसरी मरेर माया लाउँदा के पाइयो र, खै?\r\nलौ, तिमी नै राख यो कहीँ नभाको मन तिमीसँगै\r\nओ, किन गाउँछन् कुन्नि माया बारेमा?\r\nआफूलाई त पिरतीले कहिल्यै फापेन\r\nबस्दिन है म चाहिँ तिमी पर्खेर\r\nजान्छु जुन बाटो आएँ त्यही बाटो फर्केर\r\nके तालको मनपरी? आफैलाई महारानी रे\r\nकुन चाहिँले गफ लाइदियो, आफूलाई खूबै ठानिछे\r\nकि के हो, खै? तिम्रो कुरै बुझे त के भन्नु कहिले\r\nघुमाउरो कुरामा तिमीले घुमायौ, म नि घुमेँ\r\nत्यसरी मरेर माया लाउँदा केही पाइएन है\r\nलौ, तिमी नै राख त्यो कहीँ नभाको मन तिमीसँगै\r\nकिन गाउँछन् कुन्नि माया बारेमा?\r\nआफूलाई त पिरतीले कहिल्यै फापेन\r\nबस्दिन है म चाहिँ तिमी पर्खेर\r\nके जान्छु जुन बाटो आएँ त्यही बाटो फर्केर, hey!\r\nमहँगो रैछ माया तिम्रो, मलाई चाहिएन\r\nचोखो माया खोजेकै थिएँ, त्यो नि पाइएन\r\nए कान्छी, तिम्रै पछि लागी बुझेँ यस्तो पो रैछ\r\nतिम्रो माया महँगो, मुटु चाहिँ सस्तो रैछ\r\nमहँगो रैछ माया तिम्रो, मलाई चाहिएन\r\nचोखो माया खोजेकै थिएँ, त्यो नि पाइएन\r\nए कान्छी, तिम्रै पछि लागी बुझेँ यस्तो पो रैछ\r\nतिम्रो माया महँगो, मुटु चाहिँ सस्तो रैछ', 'Khaley Maya Yo\r\nDin Dinai Kamaunu Parne Re\r\nMana Le Pugdaina\r\nSirr Mathi Chadaunu Parne Re\r\n\r\nYasari Marera\r\nMaya Lauda K Paiyo Ra Khai\r\nLau Timi Nai Rakha Yo\r\nKahi Nabhako Gunn Timi Sangai\r\nOh\r\n\r\nKina Gauchan Kunni Maya Barema\r\nAafulai Ta Piratile Kahile Fapena\r\nBasdina Hai Ma Chahi Timi Parkhera\r\nJanchu Jun Bato Aaye Tyahi Bato Farkera\r\n\r\nWoah, Oh, Oh, Oh\r\nWoah, Oh, Oh, Oh\r\n\r\nK Taal Ko Manpari Aafailai Maharani Re\r\nKun Chahi Le Guff Layi Diyo Aafulai Khubai Thaniche\r\nKi K Ho Khai Timro Kurai Bhujhe Ta K Bhannu Kahile\r\nGhumauro Kurama Timley Ghumayau Ma Ni Ghume\r\n\r\nTysari Marera\r\nMaya Lauda K Paiyela Hai\r\nLau Timi Nai Rakha Tyo\r\nKahi Nabhako Gunn Timi Sangai\r\n\r\n\r\nKina Gauchan Kunni Maya Barema\r\nAfulai Ta Piratile Kahile Fapena\r\nBasdina Hai Ma Chahi Timi Parkhera\r\nJanchu Jun Bato Aaye Tyahi Bato Farkera\r\n(Hey)\r\n\r\nWoah, Oh, Oh, Oh\r\nWoah, Oh, Oh, Oh\r\n\r\nMahango Rahecha Maya Timro Malai Chahiyena\r\nChokho Maya Khojekai Thiye Tyo Ni Payiyena\r\nA Kanchi, Timrai Pachi Lagey Bujhey Yasto Po Rahecha\r\nTimro Maya Mahango Mutu Chahi Sasto Rahecha\r\n\r\nMahango Rahecha Maya Timro Malai Chahiyena\r\nChokho Maya Khojekai Thiye Tyo Ni Payiyena\r\nA Kanchi, Timrai Pachi Lagey Bujhey Yasto Po Rahecha\r\nTimro Maya Mahango Mutu Chahi Sasto Rahecha', '2026-02-02 14:56:11', '2026-02-02 14:56:11'),
(2, 3, 'घर केले छाउनू ? पराल न खर, छैन नि झिँगटी\r\nघर केले छाउनू ? पराल न खर, छैन नि झिँगटी\r\nहौ, भाग्यमै भए कमाउँछु भन्छ चार टिन सम्पत्ति\r\nहौ, भाग्यमै भए कमाउँछु भन्छ चार टिन सम्पत्ति\r\n\r\nगाई भने सानो दूध दिन्छ मानु, खानू कि नखानू ?\r\nमागेरै लाउन नसक्नेसँग जानू कि नजानू ?\r\n\r\nधान सुक्यो रापले, फकाउँछ काफ्ले, जानू कि नजानू ?\r\nधान सुक्यो रापले, फकाउँछ काफ्ले, जानू कि नजानू ?\r\n\r\nबाँझो खेतबाली लगाउँछु भन्छ हलोले जोतेर\r\nबाँझो खेतबाली लगाउँछु भन्छ हलोले जोतेर\r\nरितभाँतैबिना आँखाको चालमा नौडाँडा काटेर\r\nहौ, भगाई पो लान्छु भन्छ हौ काफ्ले, जानू कि नजानू ?\r\n\r\nधान सुक्यो रापले, फकाउँछ काफ्ले, जानू कि नजानू ?\r\nधान सुक्यो रापले, फकाउँछ काफ्ले, जानू कि नजानू ?\r\n\r\nहह​, भिर र पहिरो, खोलाको बाटो, नमान्नू डरै डर\r\nहे, भिर र पहिरो, खोलाको बाटो, नमान्नू डरै डर\r\nनफुल्नू माया, मनभरि फुल्यो यो जुनी तिम्रै भर\r\nहौ, नफुल्नू माया, मनभरि फुल्यो यो जुनी तिम्रै भर\r\n\r\nसुन है साथी, दोधारमा परेँ, के गर्नू के गर्नू ?\r\nदेखाउने माया, भगाउने माया, कुन चाहिँ पत्याउनू ?\r\n\r\nधान सुक्यो रापले, फकाउँछ काफ्ले, जानू कि नजानू ?\r\nधान सुक्यो रापले, फकाउँछ काफ्ले, जानू कि नजानू ?\r\n\r\nधान सुक्यो रापले, फकाउँछ काफ्ले, जानू कि नजानू ?\r\nधान सुक्यो रापले, फकाउँछ काफ्ले, जानू कि नजानू ?', 'Ghar Ke Le Chaunu\r\nParaal Ma Khara\r\nChaina Ni Jingati\r\nGhar Ke Le Chaunu\r\nParaal Ma Khara\r\nChaina Ni Jingati\r\n\r\nHau Bhagya Mai Bhaye\r\nKamauchu Bhancha\r\nChaar Tina Sampati\r\nHou Bhagya Mai Bhaye\r\nKamauchu Bhancha\r\nChaar Tina Sampati\r\n\r\nGaai Bhane Sano\r\nDudh Dincha Maano\r\nKhanu Ki Nakhanu\r\nMagerai Lanu\r\nNasakne Sanga\r\nJaanu Ki Najanu\r\n\r\nDhaan Sukyo Raap Le\r\nFakaucha Kafle\r\nJaanu Ki Najanu\r\nDhaan Sukyo Raap Le\r\nFakaucha Kafle\r\nJanu Ki Najanu\r\n\r\nBajoo Khet Baali\r\nLagauchu Bhancha\r\nHalo Le Jotera\r\nBajoo Khet Baali\r\nLagauchu Bhancha\r\nHalo Le Jotera\r\n\r\nReet Bhatai Dina\r\nAakha Ko Chaal Ma\r\nNau Dada Katera\r\nHau Fakai Po Lanchu\r\nBhancha Hau Kafle\r\nJaanu Ki Najaanu\r\n\r\nDhaan Sukyo Raap Le\r\nFakaucha Kafle\r\nJaanu Ki Najanu\r\nDhaan Sukyo Raap Le\r\nFakaucha Kafle\r\nJanu Ki Najanu\r\n\r\nHa Ha Bhira Ra Pahiro\r\nKhola Ko Baato\r\nNamaanu Darai Lai\r\nHey Bhira Ra Pahiro\r\nKhola Ko Baato\r\nNamaanu Darai Lai\r\n\r\nNafulnu Maya\r\nMaan Bhari Fulyo\r\nYo Juni Timrai Bho\r\nHau Nafulnu Maya\r\nMaan Bhari Fulyo\r\nYo Juni Timrai Bho\r\n\r\nSuna Hai Saathi\r\nDodhaar Ma Pare\r\nK Garnu K Garnu\r\nDekhaune Maya\r\nBhagaune Maya\r\nKunchahi Pathyanu\r\n\r\nDhaan Sukyo Raap Le\r\nFakaucha Kafle\r\nJaanu Ki Najanu\r\nDhaan Sukyo Raap Le\r\nFakaucha Kafle\r\nJanu Ki Najanu\r\n\r\nDhaan Sukyo Raap Le\r\nFakaucha Kafle\r\nJaanu Ki Najanu\r\nDhaan Sukyo Raap Le\r\nFakaucha Kafle\r\nJanu Ki Najanu', '2026-02-02 15:26:11', '2026-02-02 15:26:11'),
(3, 4, 'मेरी प्यारी माया, आशा छ तिमी ठिकै छौ\r\nअनि अझै मेरो पत्र आउँदा तिमी रुन्दैनौ\r\nधेरै भयो है हामी कुरा–कानी नभएको\r\nतिम्रो अँगालोले मेरो अँगालो सजाएको\r\n\r\nतर यति बुझ है, मलाई तिम्रो अझै\r\nसम्झनाले पिरोल्छ\r\nमेरा काँधभरि तिमीले झारेका आँसुले\r\nछातीसम्मै पोल्छ\r\n\r\nमायालु, तिमीलाई सम्झी बस्छु एकान्तमा\r\nअल्झिँदै तिमी कहिले आइपुग्ने रहरको सिमान्तमा\r\nभन्न त मन छ, पर्खी बस है\r\nतर महँगो रहेछ सपना धेरै\r\nहो र यो स्वार्थ नै, मायाको अर्थ खै?\r\n\r\nहेरिरहँदा तिम्रो मुटु तड्पेकै\r\nतर यति सम्झ है, मलाई तिम्रो अझै\r\nसुस्केरीले बिउँझाउँछ\r\nनिन्दरी पर्खँदा, फेरि तिम्रै सम्झनाले\r\nआँखा मेरो रसाउँछ\r\n\r\nमायालु, तिमीलाई सम्झी बस्छु एकान्तमा\r\nकल्पिँदै फेरि यथार्थ र रहरको सिमान्तमा\r\n\r\nआज जुना बनी आयौ, भोलि आफैँ आउनु है?\r\nतिम्रो झल–झली सम्झना, आइरहेछ नि मलाई\r\nअब अर्को भेट नभए, यति सम्झिराख है\r\nतिम्रै थिएँ म त जहिल्यै, तिम्रै हुन्छु म सधैं\r\n\r\nआज जुना बनी आयौ, भोलि आफैँ आउनु है?\r\nतिम्रो झल–झली सम्झना, आइरहेछ नि मलाई\r\nअब अर्को भेट नभए, यति सम्झिराख है\r\nतिम्रै थिएँ म त जहिल्यै, तिम्रै हुन्छु म सधैं', 'Meri pyaari Maya, aasha cha timi thikai chau\r\nAni ajhai mero patra aaundaa timi rundainau\r\nDherai bhayo hai haami kuraa kaani nabhaako\r\nTimro angaalo le meero angaalo sajaako\r\nTara yeti bujha hai, malaai timro ajhai\r\nSamjhana ley pirolcha\r\nMeraa kaandha bhari timiley jhaareykaa aansu le\r\nChaati sammai polcha\r\nMayaloo, timilaai samjhi baschu ekaantamaa\r\nAljhindai timi kahin aaipugney rahar ko simaanta maa\r\nBhanna ta mann cha, parkhi basa hai\r\nTara mahango raicha sapana dherai\r\nHo ra yo swaartha nai, maya ko artha khai?\r\nHerirahana timro mutu tadpekai\r\nTara yeti samjha hai, malaai timro ajhai\r\nSuskeri ley biunjhaauncha\r\nNindari parkhandaa, pheri timrai samjhanaa ley\r\nAakhaa mero rasaauncha\r\nMayaloo, timilaai samjhi baschu ekaantamaa\r\nKalpindai feri yathartha ra rahar ko simaanta maa\r\nAaja juna bani aayau, bholi aafai aaunu hai?\r\nTimro jhal-jhali samjhana, aayirahecha ni malai\r\nAba arko bhet nabhaye, yeti samjhiraakha hai\r\nTimrai thiyen ma ta jahiley, timrai hunchu ma sandhai\r\nAaja juna bani aayau, bholi aafai aaunu hai?\r\nTimro jhal-jhali samjhana, aayirahecha ni malai\r\nAba arko bhet nabhaye, yeti samjhiraakha hai\r\nTimrai thiyen ma ta jahiley, timrai hunchu ma sandhai', '2026-02-02 17:14:48', '2026-02-02 17:14:48'),
(4, 5, 'It\'s been a long day without you, my friend\r\nAnd I\'ll tell you all about it when I see you again\r\nWe\'ve come a long way from where we began\r\nOh, I\'ll tell you all about it when I see you again\r\nWhen I see you again\r\n\r\nDamn, who knew?\r\nAll the planes we flew\r\nGood things we been through\r\nThat I\'d be standing right here talking to you\r\n\'Bout another path\r\nI know we loved to hit the road and laugh\r\nBut something told me that it wouldn\'t last\r\nHad to switch up\r\nLook at things different, see the bigger picture\r\nThose were the days\r\nHard work forever pays\r\nNow I see you in a better place, uh\r\n\r\nHow can we not talk about family\r\nWhen family\'s all that we got?\r\nEverything I went through\r\nYou were standing there by my side\r\nAnd now you gon\' be with me for the last ride\r\n\r\nIt\'s been a long day without you, my friend\r\nAnd I\'ll tell you all about it when I see you again\r\nWe\'ve come a long way from where we began\r\nOh, I\'ll tell you all about it when I see you again\r\nWhen I see you again\r\n\r\nAah oh, aah oh\r\nWooooh-oh-oh-oh-oh-oh\r\nYeah\r\n\r\nFirst, you both go out your way\r\nAnd the vibe is feeling strong\r\nAnd what\'s small turned to a friendship\r\nA friendship turned to a bond\r\nAnd that bond will never be broken\r\nThe love will never get lost\r\nAnd when brotherhood come first\r\nThen the line will never be crossed\r\nEstablished it on our own\r\nWhen that line had to be drawn\r\nAnd that line is what we reached\r\nSo remember me when I\'m gone\r\n\r\nHow can we not talk about family\r\nWhen family\'s all that we got?\r\nEverything I went through\r\nYou were standing there by my side\r\nAnd now you gon\' be with me for the last ride\r\n\r\nSo let the light guide your way, yeah\r\nHold every memory as you go\r\nAnd every road you take\r\nWill always lead you home, home\r\n\r\nIt\'s been a long day without you, my friend\r\nAnd I\'ll tell you all about it when I see you again\r\nWe\'ve come a long way from where we began\r\nOh, I\'ll tell you all about it when I see you again\r\nWhen I see you again\r\n\r\nAah oh, aah oh\r\nWooooh-oh-oh-oh-oh-oh\r\nWhen I see you again\r\n\r\nAah oh, aah oh\r\nWooooh-oh-oh-oh-oh-oh\r\nWhen I see you again', NULL, '2026-02-03 10:58:54', '2026-02-03 10:58:54');
